mapper.select:
select sm.id, sm.subject_id as subjectId, s.code as subjectCode, s.name as subjectName, st.code as subjectTypeCode, st.name as subjectTypeName, sm.is_default as isDefault, sm.account_id as accountId, a.realm_id as realmId, r.code as realmCode, r.name as realmName, a.username, a.mobile, a.email, sm.member_type as memberType, case sm.member_type when 1 then 'OWNER' when 2 then 'ADMIN' when 3 then 'MEMBER' when 4 then 'STAFF' else 'UNKNOWN' end as memberTypeName, sm.display_name as displayName, sm.remark, sm.status as memberStatus, a.status as accountStatus, sm.joined_at as joinedAt, sm.joined_by_account_id as joinedByAccountId, joined_by.username as joinedByUsername, sm.disabled_at as disabledAt, sm.removed_at as removedAt, sm.create_time, sm.update_time from subject_member sm inner join subject s on s.id = sm.subject_id left join subject_type st on st.id = s.subject_type_id inner join account a on a.id = sm.account_id left join realm r on r.id = a.realm_id left join account joined_by on joined_by.id = sm.joined_by_account_id
and sm.subject_id = #{request.subjectId}
and sm.account_id = #{request.accountId}
and ( a.username like concat('%', #{request.keyword}, '%') or a.mobile like concat('%', #{request.keyword}, '%') or a.email like concat('%', #{request.keyword}, '%') or sm.display_name like concat('%', #{request.keyword}, '%') )
and sm.member_type = #{request.memberType}
and sm.status = #{request.memberStatus}
and a.status = #{request.accountStatus}
and a.realm_id = #{request.realmId}
and sm.joined_at >= #{request.joinedStartAt}
and sm.joined_at <= #{request.joinedEndAt}
order by sm.joined_at desc, sm.create_time desc

select account_id, count(1) as count from subject_member where account_id in
#{id}
and status != 3 group by account_id

mapper.update:
update subject_member
set is_default = 1
where id = #{id}
